@using sv_797a57dbcab64927a3e4868cf0b78b8a.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

<div class="row">
    @* ── Left sidebar: filters ── *@
    <div class="col-md-3">
        <div class="card">
            <div class="card-header fw-bold">Filters</div>
            <div class="card-body">
                @* Category checkboxes *@
                <h6>Category</h6>
                @if (_categories is not null)
                {
                    @foreach (var cat in _categories)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="checkbox" id="@($"cat-{cat}")"
                                   checked="@_selectedCategories.Contains(cat)"
                                   @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
                            <label class="form-check-label" for="@($"cat-{cat}")">@cat</label>
                        </div>
                    }
                }

                <hr />

                @* Price range *@
                <h6>Price Range</h6>
                <div class="mb-2">
                    <label class="form-label small">Min Price</label>
                    <input type="number" class="form-control form-control-sm" @bind="_minPrice" min="0" step="0.01" />
                </div>
                <div class="mb-2">
                    <label class="form-label small">Max Price</label>
                    <input type="number" class="form-control form-control-sm" @bind="_maxPrice" min="0" step="0.01" />
                </div>

                <hr />

                @* In Stock toggle *@
                <div class="form-check mb-3">
                    <input class="form-check-input" type="checkbox" id="inStockOnly" @bind="_inStockOnly" />
                    <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                </div>

                @* Action buttons *@
                <button class="btn btn-primary w-100 mb-2" @onclick="ApplyFilters">Apply Filters</button>
                <button class="btn btn-outline-secondary w-100" @onclick="ClearFilters">Clear Filters</button>
            </div>
        </div>
    </div>

    @* ── Main content area ── *@
    <div class="col-md-9">
        @if (_errorMessage is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @_errorMessage
            </div>
        }
        else if (_isLoading)
        {
            <div class="d-flex justify-content-center align-items-center" style="min-height: 300px;">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else if (_result is null || _result.Items.Count == 0)
        {
            <div class="alert alert-info text-center" role="alert">
                No products found matching your criteria.
            </div>
        }
        else
        {
            @* Toolbar *@
            <div class="d-flex justify-content-between align-items-center mb-3">
                <div>
                    <label class="form-label small mb-0 me-1">Sort by:</label>
                    <select class="form-select form-select-sm d-inline-block w-auto" @bind="_sortBy" @bind:after="LoadProducts">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A-Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="text-muted small">
                    Showing @((_result.Page - 1) * _result.PageSize + 1)–@(Math.Min(_result.Page * _result.PageSize, _result.TotalCount))
                    of @_result.TotalCount products
                </span>
            </div>

            @* Product grid *@
            <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3 mb-3">
                @foreach (var product in _result.Items)
                {
                    <div class="col">
                        <ProductCard Product="product"
                                     OnProductSelected="HandleProductSelected"
                                     OnAddToCart="HandleAddToCart" />
                    </div>
                }
            </div>

            @* Pagination *@
            @{
                int totalPages = (int)Math.Ceiling((double)_result.TotalCount / _result.PageSize);
            }
            @if (totalPages > 1)
            {
                <nav aria-label="Product pagination">
                    <ul class="pagination justify-content-center">
                        <li class="page-item @(_currentPage == 1 ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPage(_currentPage - 1)" disabled="@(_currentPage == 1)">Previous</button>
                        </li>
                        @for (int i = 1; i <= totalPages; i++)
                        {
                            int pageNum = i;
                            <li class="page-item @(pageNum == _currentPage ? "active" : "")">
                                <button class="page-link" @onclick="() => GoToPage(pageNum)">@pageNum</button>
                            </li>
                        }
                        <li class="page-item @(_currentPage == totalPages ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPage(_currentPage + 1)" disabled="@(_currentPage == totalPages)">Next</button>
                        </li>
                    </ul>
                </nav>
            }
        }
    </div>
</div>

@code {
    /// <summary>Raised when a product card (not the Add to Cart button) is clicked.</summary>
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string>? _categories;
    private HashSet<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int PageSize = 9;

    private PagedResult<Product>? _result;
    private bool _isLoading;
    private string? _errorMessage;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _isLoading = true;
            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = ProductService.SearchAsync(BuildFilter(), _sortBy, _currentPage, PageSize);
            await Task.WhenAll(categoriesTask, productsTask);
            _categories = categoriesTask.Result;
            _result = productsTask.Result;
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
        finally
        {
            _isLoading = false;
        }
    }

    private ProductFilter BuildFilter() => new(
        Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
        MinPrice: _minPrice,
        MaxPrice: _maxPrice,
        InStockOnly: _inStockOnly
    );

    private async Task LoadProducts()
    {
        try
        {
            _isLoading = true;
            _errorMessage = null;
            _result = await ProductService.SearchAsync(BuildFilter(), _sortBy, _currentPage, PageSize);
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
        finally
        {
            _isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task GoToPage(int page)
    {
        _currentPage = page;
        await LoadProducts();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Hook for cart logic
        return Task.CompletedTask;
    }
}
"}

