@code {
    /// <summary>Raised when a product card (not the Add to Cart button) is clicked.</summary>
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string>? _categories;
    private HashSet<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int PageSize = 9;

    private PagedResult<Product>? _result;
    private bool _isLoading;
    private string? _errorMessage;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _isLoading = true;
            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = ProductService.SearchAsync(BuildFilter(), _sortBy, _currentPage, PageSize);
            await Task.WhenAll(categoriesTask, productsTask);
            _categories = categoriesTask.Result;
            _result = productsTask.Result;
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
        finally
        {
            _isLoading = false;
        }
    }

    private ProductFilter BuildFilter() => new(
        Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
        MinPrice: _minPrice,
        MaxPrice: _maxPrice,
        InStockOnly: _inStockOnly
    );

    private async Task LoadProducts()
    {
        try
        {
            _isLoading = true;
            _errorMessage = null;
            _result = await ProductService.SearchAsync(BuildFilter(), _sortBy, _currentPage, PageSize);
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
        finally
        {
            _isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task GoToPage(int page)
    {
        _currentPage = page;
        await LoadProducts();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Hook for cart logic
        return Task.CompletedTask;
    }
}

